```javascript
function calcTerritory(n, flat_conv, flat_assim, pct_conv, pct_assim) {
  if (n <= 0) return { t_conv: 0, t_assim: 0 };

  const n_half = Math.ceil(n / 2); // pops needed to cross 50% threshold

  // Velocities in each regime
  const vc_A = flat_conv * (1 + (pct_conv - 55) / 100); // before 50% conv
  const vc_B = flat_conv * (1 + (pct_conv - 30) / 100); // after 50% conv
  const va_A = flat_assim * (1 + (pct_assim - 68) / 100); // ph1, before 50% conv
  const va_B = flat_assim * (1 + (pct_assim - 58) / 100); // ph1, after 50% conv
  const va_C = flat_assim * (1 + (pct_assim - 25) / 100); // ph2, all converted

  if (vc_A <= 0 || vc_B <= 0) return null; // invalid

  // Time to convert first n_half pops
  const t_half = n_half * 100 / vc_A;
  // Time to convert remaining pops
  const t_conv = t_half + (n - n_half) * 100 / vc_B;

  // Assimilation accumulated during [0, t_half]
  const assim_A = Math.min(n, t_half * va_A / 100);
  // Assimilation accumulated during [t_half, t_conv]
  const assim_B_delta = Math.min(n - assim_A, (t_conv - t_half) * va_B / 100);
  const assim_at_conv = assim_A + assim_B_delta;

  let t_assim;
  if (assim_at_conv >= n) {
    // Assimilation finished before conversion completed
    // Find exact time in phase A or B
    if (assim_A >= n) {
      t_assim = n * 100 / va_A;
    } else {
      const remaining = n - assim_A;
      t_assim = t_half + remaining * 100 / va_B;
    }
  } else {
    // Assimilation finishes in phase C (after conversion)
    const remaining = n - assim_at_conv;
    if (va_C <= 0) return null;
    t_assim = t_conv + remaining * 100 / va_C;
  }

  return { t_conv, t_assim };
}
```

